TION_PRACTICE.CROPLAND_ACREAGE CPLD_ACRG,CONTRACT_CONSERVATION_PRACTICE.NON_CROPLAND_ACREAGE NON_CPLD_ACRG,CONTRACT_CONSERVATION_PRACTICE.CONSERVATION_ELIGIBILITY_AREA_CODE CNSV_ELG_AR_TYPE_CD,CONTRACT_CONSERVATION_PRACTICE.DATA_STATUS_CODE DATA_STAT_CD,CONTRACT_CONSERVATION_PRACTICE.CREATION_DATE CRE_DT,CONTRACT_CONSERVATION_PRACTICE.CREATION_USER_NAME CRE_USER_NM,CONTRACT_CONSERVATION_PRACTICE.LAST_CHANGE_DATE LAST_CHG_DT,CONTRACT_CONSERVATION_PRACTICE.LAST_CHANGE_USER_NAME LAST_CHG_USER_NM,SIGNUP_TYPE.op,7 AS TBL_PRIORITYFROM "fsa-{env}-ccms-cdc".SIGNUP_TYPELEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP SIGNUP ON (SIGNUP_TYPE.SIGNUP_TYPE_CODE = SIGNUP.SIGNUP_TYPE_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".MASTER_CONTRACT MASTER_CONTRACT ON (SIGNUP.SIGNUP_IDENTIFIER = MASTER_CONTRACT.SIGNUP_IDENTIFIER) LEFT JOIN "fsa-{env}-ccms-cdc".SIGNUP_SUB_CATEGORY SIGNUP_SUB_CATEGORY ON (SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_CODE = SIGNUP.SIGNUP_SUB_CATEGORY_CODE)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_DETAIL CONTRACT_DETAIL ON (MASTER_CONTRACT.CONTRACT_IDENTIFIER = CONTRACT_DETAIL.CONTRACT_IDENTIFIER)LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_FARM_TRACT CONTRACT_FARM_TRACT ON  (CONTRACT_DETAIL.CONTRACT_DETAIL_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_DETAIL_IDENTIFIER) LEFT JOIN "fsa-{env}-ccms-cdc".CONTRACT_COMMON_LAND_UNIT CONTRACT_COMMON_LAND_UNIT ON (CONTRACT_COMMON_LAND_UNIT.CONTRACT_FARM_TRACT_IDENTIFIER = CONTRACT_FARM_TRACT.CONTRACT_FARM_TRACT_IDENTIFIER)JOIN "fsa-{env}-ccms-cdc".CONTRACT_CONSERVATION_PRACTICE CONTRACT_CONSERVATION_PRACTICE ON  (CONTRACT_CONSERVATION_PRACTICE.CLU_IDENTIFIER = CONTRACT_COMMON_LAND_UNIT.CLU_IDENTIFIER)WHERE SIGNUP_TYPE.op <> 'D'UNIONSELECT MASTER_CONTRACT.ADMINISTRATIVE_STATE_FSA_CODE ADM_ST_FSA_CD,MASTER_CONTRACT.ADMINISTRATIVE_COUNTY_FSA_CODE ADM_CNTY_FSA_CD,SIGNUP_TYPE.SIGNUP_TYPE_NAME SGNP_TYPE_NM,SIGNUP_SUB_CATEGORY.SIGNUP_SUB_CATEGORY_NAME SGNP_SUB_CAT_NM,SIGNUP.signup_number SGNP_NBR,SIGNUP.SIGNUP_SUBTYPE_AGREEMENT_NAM